import React, { useRef } from "react";

interface ImportModalProps {
  isOpen: boolean;
  onClose: () => void;
  importType: string | null;
  setImportType: (type: any) => void;
  selectedFiles: File[];
  setSelectedFiles: (files: File[]) => void;
  uploadProgress: number;
  setUploadProgress: (progress: number) => void;
  isUploading: boolean;
  setIsUploading: (uploading: boolean) => void;
}

const ImportModal: React.FC<ImportModalProps> = ({ 
  isOpen, 
  onClose, 
  importType, 
  setImportType, 
  selectedFiles, 
  setSelectedFiles,
  uploadProgress,
  setUploadProgress,
  isUploading,
  setIsUploading
}) => {
  const fileInputRef = useRef<HTMLInputElement>(null);

  const importOptions = [
    { 
      id: 'raw', 
      title: 'Fichier Brut', 
      icon: 'fa-file-import', 
      color: 'from-blue-500 to-blue-600',
      description: 'PDF, Audio, Image',
      accepted: '.pdf,.mp3,.wav,.mp4,.jpg,.jpeg,.png'
    },
    { 
      id: 'transcription', 
      title: 'Transcription', 
      icon: 'fa-keyboard', 
      color: 'from-green-500 to-green-600',
      description: 'Texte transcrit',
      accepted: '.txt,.doc,.docx'
    },
    { 
      id: 'book', 
      title: 'Projet de Livre', 
      icon: 'fa-book', 
      color: 'from-purple-500 to-purple-600',
      description: 'Assemblage de transcriptions',
      accepted: '.txt,.doc,.docx,.pdf'
    },
    { 
      id: 'proofreading1', 
      title: 'Relecture 1', 
      icon: 'fa-eye', 
      color: 'from-amber-500 to-amber-600',
      description: 'Première relecture',
      accepted: '.txt,.doc,.docx,.pdf'
    },
    { 
      id: 'proofreading2', 
      title: 'Relecture 2', 
      icon: 'fa-eye-double', 
      color: 'from-red-500 to-red-600',
      description: 'Seconde relecture',
      accepted: '.txt,.doc,.docx,.pdf'
    },
  ];

  const handleFileSelect = (e: React.ChangeEvent<HTMLInputElement>) => {
    if (e.target.files) {
      setSelectedFiles(Array.from(e.target.files));
    }
  };

  const handleDrop = (e: React.DragEvent) => {
    e.preventDefault();
    if (e.dataTransfer.files) {
      setSelectedFiles(Array.from(e.dataTransfer.files));
    }
  };

  const handleUpload = async () => {
    if (selectedFiles.length === 0 || !importType) return;
    
    setIsUploading(true);
    setUploadProgress(0);
    
    // Simulation d'upload
    for (let i = 0; i <= 100; i += 10) {
      setUploadProgress(i);
      await new Promise(resolve => setTimeout(resolve, 200));
    }
    
    setIsUploading(false);
    alert(`✅ ${selectedFiles.length} fichier(s) importé(s) avec succès !`);
    onClose();
  };

  const currentOption = importOptions.find(opt => opt.id === importType);

  return (
    <div className="fixed inset-0 z-[100] flex items-center justify-center p-4">
      {/* Overlay */}
      <div 
        className="absolute inset-0 bg-black bg-opacity-50 backdrop-blur-sm animate-fade-in"
        onClick={onClose}
      ></div>
      
      {/* Modale */}
      <div className="relative bg-white dark:bg-gray-800 rounded-2xl shadow-2xl max-w-4xl w-full max-h-[90vh] overflow-y-auto animate-scale-in">
        {/* En-tête */}
        <div className="sticky top-0 bg-gradient-to-r from-purple-600 to-indigo-600 text-white px-6 py-4 rounded-t-2xl flex justify-between items-center">
          <h2 className="text-2xl font-bold flex items-center gap-3">
            <i className="fas fa-upload"></i>
            Importer des Fichiers
          </h2>
          <button 
            onClick={onClose}
            className="p-2 hover:bg-white/20 rounded-lg transition-colors"
          >
            <i className="fas fa-times text-xl"></i>
          </button>
        </div>

        <div className="p-6">
          {/* Étape 1 : Choisir le type */}
          <div className="mb-6">
            <h3 className="text-lg font-semibold text-gray-900 dark:text-white mb-4 flex items-center gap-2">
              <span className="w-8 h-8 bg-purple-100 dark:bg-purple-900/30 text-purple-600 dark:text-purple-400 rounded-full flex items-center justify-center text-sm font-bold">1</span>
              Choisissez le type de fichier
            </h3>
            
            <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 gap-4">
              {importOptions.map((option) => (
                <button
                  key={option.id}
                  onClick={() => {
                    setImportType(option.id);
                    setSelectedFiles([]);
                  }}
                  className={`p-4 rounded-xl border-2 transition-all duration-200 text-left ${
                    importType === option.id
                      ? `border-${option.color.split('-')[1]}-500 bg-${option.color.split('-')[1]}-50 dark:bg-${option.color.split('-')[1]}-900/20`
                      : 'border-gray-200 dark:border-gray-700 hover:border-purple-300 dark:hover:border-purple-500'
                  }`}
                >
                  <div className={`w-12 h-12 bg-gradient-to-br ${option.color} rounded-xl flex items-center justify-center mb-3`}>
                    <i className={`fas ${option.icon} text-white text-xl`}></i>
                  </div>
                  <h4 className="font-semibold text-gray-900 dark:text-white">{option.title}</h4>
                  <p className="text-sm text-gray-500 dark:text-gray-400 mt-1">{option.description}</p>
                </button>
              ))}
            </div>
          </div>

          {/* Étape 2 : Sélectionner les fichiers */}
          {importType && currentOption && (
            <div className="mb-6">
              <h3 className="text-lg font-semibold text-gray-900 dark:text-white mb-4 flex items-center gap-2">
                <span className="w-8 h-8 bg-purple-100 dark:bg-purple-900/30 text-purple-600 dark:text-purple-400 rounded-full flex items-center justify-center text-sm font-bold">2</span>
                Sélectionnez vos fichiers
              </h3>
              
              {/* Zone de drop */}
              <div
                onDrop={handleDrop}
                onDragOver={(e) => e.preventDefault()}
                onClick={() => fileInputRef.current?.click()}
                className="border-2 border-dashed border-gray-300 dark:border-gray-600 rounded-xl p-8 text-center cursor-pointer hover:border-purple-500 dark:hover:border-purple-400 transition-colors bg-gray-50 dark:bg-gray-700/50"
              >
                <input
                  ref={fileInputRef}
                  type="file"
                  multiple
                  accept={currentOption.accepted}
                  onChange={handleFileSelect}
                  className="hidden"
                />
                <i className="fas fa-cloud-upload-alt text-5xl text-gray-400 mb-4"></i>
                <p className="text-lg font-medium text-gray-700 dark:text-gray-300 mb-2">
                  Glissez-déposez vos fichiers ici
                </p>
                <p className="text-sm text-gray-500 dark:text-gray-400 mb-4">
                  ou cliquez pour parcourir
                </p>
                <p className="text-xs text-gray-400 dark:text-gray-500">
                  Formats acceptés : {currentOption.accepted}
                </p>
              </div>

              {/* Fichiers sélectionnés */}
              {selectedFiles.length > 0 && (
                <div className="mt-4 space-y-2">
                  <p className="text-sm font-medium text-gray-700 dark:text-gray-300">
                    {selectedFiles.length} fichier(s) sélectionné(s)
                  </p>
                  {selectedFiles.map((file, index) => (
                    <div 
                      key={index}
                      className="flex items-center justify-between bg-gray-50 dark:bg-gray-700 rounded-lg p-3"
                    >
                      <div className="flex items-center gap-3">
                        <i className="fas fa-file text-gray-400"></i>
                        <div>
                          <p className="text-sm font-medium text-gray-900 dark:text-white">{file.name}</p>
                          <p className="text-xs text-gray-500 dark:text-gray-400">
                            {(file.size / 1024 / 1024).toFixed(2)} MB
                          </p>
                        </div>
                      </div>
                      <button
                        onClick={() => setSelectedFiles(selectedFiles.filter((_, i) => i !== index))}
                        className="text-gray-400 hover:text-red-500 transition-colors"
                      >
                        <i className="fas fa-times"></i>
                      </button>
                    </div>
                  ))}
                </div>
              )}
            </div>
          )}

          {/* Étape 3 : Progression */}
          {isUploading && (
            <div className="mb-6">
              <h3 className="text-lg font-semibold text-gray-900 dark:text-white mb-4 flex items-center gap-2">
                <span className="w-8 h-8 bg-purple-100 dark:bg-purple-900/30 text-purple-600 dark:text-purple-400 rounded-full flex items-center justify-center text-sm font-bold">3</span>
                Progression de l'upload
              </h3>
              
              <div className="bg-gray-100 dark:bg-gray-700 rounded-full h-4 overflow-hidden">
                <div 
                  className="h-full bg-gradient-to-r from-purple-600 to-indigo-600 transition-all duration-300"
                  style={{ width: `${uploadProgress}%` }}
                >
                  <div className="h-full animate-pulse bg-white/20"></div>
                </div>
              </div>
              <p className="text-center text-sm text-gray-600 dark:text-gray-400 mt-2">
                {uploadProgress}% complété
              </p>
            </div>
          )}

          {/* Boutons d'action */}
          <div className="flex justify-end gap-3 pt-6 border-t border-gray-200 dark:border-gray-700">
            <button
              onClick={onClose}
              className="px-6 py-3 bg-gray-200 dark:bg-gray-700 hover:bg-gray-300 dark:hover:bg-gray-600 text-gray-800 dark:text-gray-200 rounded-xl font-medium transition-all duration-200"
            >
              Annuler
            </button>
            <button
              onClick={handleUpload}
              disabled={selectedFiles.length === 0 || isUploading}
              className="px-6 py-3 bg-gradient-to-r from-purple-600 to-indigo-600 hover:from-purple-700 hover:to-indigo-700 disabled:from-gray-400 disabled:to-gray-500 text-white rounded-xl font-medium transition-all duration-200 flex items-center gap-2 disabled:cursor-not-allowed shadow-lg hover:shadow-xl"
            >
              {isUploading ? (
                <>
                  <i className="fas fa-spinner fa-spin"></i>
                  Import en cours...
                </>
              ) : (
                <>
                  <i className="fas fa-upload"></i>
                  Importer {selectedFiles.length > 0 && `(${selectedFiles.length})`}
                </>
              )}
            </button>
          </div>
        </div>
      </div>
    </div>
  );
};

export default ImportModal;
